/**
 * Geolocation utilities for Next.js middleware and edge functions.
 *
 * Extracts geolocation data from common CDN/proxy headers
 * (Vercel, Cloudflare, etc.).
 */

export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

const COUNTRY_NAMES: Record<string, string> = {
  US: 'United States',
  GB: 'United Kingdom',
  DE: 'Germany',
  FR: 'France',
  JP: 'Japan',
  CN: 'China',
  IN: 'India',
  BR: 'Brazil',
  AU: 'Australia',
  CA: 'Canada',
}

function extractGeo(headers: Headers): Geo {
  const city = headers.get('x-vercel-ip-city') || undefined
  const region = headers.get('x-vercel-ip-country-region') || undefined
  const latitude = headers.get('x-vercel-ip-latitude') || undefined
  const longitude = headers.get('x-vercel-ip-longitude') || undefined
  const timezone = headers.get('x-vercel-ip-timezone') || undefined

  // Vercel header takes precedence, Cloudflare as fallback
  const countryCode =
    headers.get('x-vercel-ip-country') ||
    headers.get('cf-ipcountry') ||
    undefined

  const country = countryCode
    ? COUNTRY_NAMES[countryCode.toUpperCase()] || undefined
    : undefined

  return {
    city,
    country,
    countryCode,
    region,
    latitude,
    longitude,
    timezone,
  }
}

/**
 * Extracts geolocation data from a request object's headers.
 * Reads common CDN/proxy headers (Vercel, Cloudflare).
 */
export function geo(req: { headers: Headers }): Geo {
  return extractGeo(req.headers)
}

/**
 * Extracts geolocation data from raw Headers.
 * Same logic as `geo()`, but accepts Headers directly.
 */
export function geoFromHeaders(headers: Headers): Geo {
  return extractGeo(headers)
}

/**
 * Checks if the given geo's countryCode is in the provided list of regions.
 * Comparison is case-insensitive.
 */
export function isInRegion(geoData: Geo, regions: string[]): boolean {
  if (!geoData.countryCode) {
    return false
  }
  const code = geoData.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

/**
 * Calculates the Haversine distance in kilometers between two points
 * specified by their latitude and longitude strings.
 */
export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371 // Earth's radius in kilometers
  const toRad = (deg: number): number => (deg * Math.PI) / 180

  const φ1 = toRad(parseFloat(lat1))
  const φ2 = toRad(parseFloat(lat2))
  const Δφ = toRad(parseFloat(lat2) - parseFloat(lat1))
  const Δλ = toRad(parseFloat(lon2) - parseFloat(lon1))

  const a =
    Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
    Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2)
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))

  return R * c
}

